mod lib {
    pub fn target(code: i32) -> i32 {
        if code < 0 {
            return 7;
        }
        let m: i32 = code % 10;
        if m == 0 {
            return 0;
        }
        if m <= 3 {
            return 1;
        }
        if m <= 6 {
            return 2;
        }
        if m == 7 {
            return 3;
        }
        4
    }
}

mod a {
