    }

    thread_local! {
        static STATE_A: Cell<i32> = const { Cell::new(0) };
    }

    fn target(code: i32) -> i32 {
        if code < 0 {
            return STATE_A.with(|s| if (s.get() & 1) != 0 { 6 } else { 5 });
        }
