            0 => 0,
            1 => 2,
            2 => 4,
            3 => 1,
            4 => 3,
            5 | 6 => 5,
            _ => 7,
        }
    }

    #[inline]
    fn wrap(x: i32) -> i32 {
        target(x - 5)
    }

    pub fn call_a_once(x: i32) -> i32 {
        let a: i32 = target(x);
